const body = $json.body || $json;
const workpack = body.workpack || {};
const channels = Array.isArray(body.channels) && body.channels.length ? body.channels : ['email'];
const recipients = Array.isArray(body.recipients) ? body.recipients : [];
const results = channels.map((channel) => ({
  channel,
  status: 'unconfigured',
  message: `${channel} provider credential is not configured yet`
}));
return [{
  json: {
    ok: true,
    workflowRunId: $execution.id,
    providerStatus: 'unconfigured',
    channelResults: results,
    summary: {
      requested: channels.length,
      sent: 0,
      failed: 0,
      unconfigured: results.length
    },
    subject: `[SafeGuard] ${workpack.companyName || workpack.siteName || '현장'} 작업 전 문서팩`,
    recipients,
    message: 'SafeGuard 전파 요청은 접수됐지만 채널 provider 키가 아직 설정되지 않았습니다.',
    messagePreview: String(workpack.message || '').slice(0, 240),
    acceptedPayload: {
      channels,
      recipients,
      operatorNote: body.operatorNote || '',
      messageTarget: workpack.messageTarget || 'manager',
      messageLanguage: workpack.messageLanguage || { code: 'ko', label: '한국어' }
    }
  }
}];

return [{
  json: {
    ok: false,
    providerStatus: 'rejected',
    message: 'SafeGuard secret header is missing or invalid.'
  }
}];
